%[text] # Tutorial on Matlab Graphs
%[text:tableOfContents]{"heading":"Table of Contents"}
%[text] 
%%
%[text] ## A Rocket
%[text] ### `plot()` 활용하기
%[text] 아래 그래프를 그리려고 합니다. 
%[text] ![](text:image:68d5)
%[text] - Step 1: A ~ E 까지 좌표를 행렬 C에 기록합니다.
%[text] - Step 2: plot으로 그래프를 그립니다.
%[text] - Step 3: 이런... 어떻게 하면 될까요? \
%%
%[text] ### LiveScript에서 탈출하기
%[text] 그래프가 LiveScript에서 튀어 나오게 하려면..
% Visible --> on
C = [-1, -1; 1, 1; 5, 0; 1, -1; -1, 1,; -1, -1];
x = C(:,1); %[output:4ad854e9]
y = C(:,2);
figure("Visible", "On"); %[output:68906783]
h = plot(x, y, 'b-o', 'LineWidth', 2); %[output:68906783]
h.MarkerFaceColor = 'blue'; %[output:68906783]
h.MarkerEdgeColor = 'blue'; %[output:68906783]
axis([-1 5 -2 2]); %[output:68906783]
grid on; axis equal; %[output:68906783]

xlabel("나는 x축"); %[output:68906783]
ylabel("y"); %[output:68906783]

text(-1, -0.8, "A"); %[output:68906783]
text(1, -0.8, "D"); %[output:68906783]
text(5, 0.2, "C"); %[output:68906783]
text(1, 1.2, "B"); %[output:68906783]
text(-1, 1.2, "E", 'Color', 'red'); %[output:68906783]

title("아르테미스"); %[output:68906783]
%%
%[text] ### 미니멀리즘
%[text] 축과 배경 모두 사라지게 하려면..
axis off %타이틀은 남는다 %[output:84a586e3]
%%
%[text] ### 이미 그려져 있는 그래프 속성 바꾸기
%[text] 마커 색깔을 바꾸어 볼까요~
%[text] ![](text:image:11aa)
% Use handle and manipulate the properties
set(h, 'MarkerFaceColor', 'blue', "MarkerEdgeColor", 'blue'); %[output:3599b50a]
% h.MarkerFaceColor = 'blue'
%%
%[text] ### 움직이는 그림
%[text] 데이터를 바꾸면 그림이 움직일까요?
%[text] 점 C의 x-좌표값을 1 ~5까지 점점 늘려보겠습니다. 
for k=1:200
     h.XData(3) = 1 + k/50; %h의 x 데이터의 인덱스 3(점C)를 1~5까지
     pause(0.1); %0.1초씩 멈춰라
 end
%%
%[text] ### Text Annotation
x = [-1 1 5 1 -1 -1];
y = [-1 1 0 -1 1 -1];
plot(x, y, 'r-o', 'LineWidth', 2); %[output:07cf8d7b]
axis equal; grid on; %[output:07cf8d7b]
text(-0.8, -1, "A");text(1.2, 1.2, "B"); %[output:07cf8d7b]
text(4.7, 0.3, "C");text(1,-0.7, "D"); %[output:07cf8d7b]
text(-0.8, 1, "E"); %[output:07cf8d7b]
%%
%[text] ## Euler Trails
%[text] ### 한 붓 그리기 (Euler Trails)
%[text] 홀수 점이 0개 또는 2개일 때 한 붓 그리기가 가능합니다.
%[text] 아래 그림들을 한 붓 그리기로 그려보세요.
%[text] ![](text:image:844d)
% Euler Trails
clear;
x = [2 -1 5 2 2 5 5 2 -1 -1 2];
y = [0 1 1 0 -2 -1 1 2 1 -1 -2];
plot(x, y) %[output:444a626d]
axis([-1 5 -2 2]); %[output:444a626d]
axis off; %[output:444a626d]
%%
clear;

d = [0 -1 -2.5 0 0 1 2.5 0 0 -2.5 -2 0 2 2.5 0];
h = [3 4 1 0 3 4 1 0 -3 -2 -4 -3 -4 -2 -3];
plot(d, h); %[output:0906dc07]
axis([-4 4 -4 4]); %[output:0906dc07]
axis off %[output:0906dc07]
%%
%[text] ## Polygram
%[text] [https://mathcurve.com/courbes3d.gb/polygramme/polygramme.shtml](https://mathcurve.com/courbes3d.gb/polygramme/polygramme.shtml)
%[text] ![](text:image:7fd0)![](text:image:676a)![](text:image:2375)![](text:image:586b)
% Draw a gray circle
clear;
t = linspace(0, 2*pi, 100);
x = cos(t);  y = sin(t);
plot(x,y,'-', "Color",0.9*[1 1 1]); %[output:1ff5b5e3]
axis equal; %[output:1ff5b5e3]
hold on; %[output:1ff5b5e3]
m = 40; %[control:slider:98a0]{"position":[5,7]}
n = 6; %[control:slider:052e]{"position":[5,6]}
k = 2*(0:m);
xa = cos(2*pi*k/m+pi/2);
ya = sin(2*pi*k/m+pi/2);
plot(xa,ya,'LineWidth',2); %[output:1ff5b5e3]
hold off; %[output:1ff5b5e3]
%%
clear;

figure; %[output:8234bc50]

n= 8;
t = 2*pi/n*(0:n);
x = cos(t);  
y = sin(t);

plot(x,y); %[output:8234bc50]
axis equal; axis off; %[output:8234bc50]
r = cos(pi/n);
a = linspace(0, 2*pi, 100);
hold on; %[output:8234bc50]
plot(r*cos(a), r*sin(a), 'r-'); %[output:8234bc50]
plot(cos(a), sin(a), 'k-'); %[output:8234bc50]
hold off; %[output:8234bc50]
%%
clear;

figure; %[output:10e1b7a0]

n= 5;
t = 4*pi/n*(0:n);
x = cos(t);  
y = sin(t);

plot(x,y); %[output:10e1b7a0]
axis equal; %[output:10e1b7a0]
r = sqrt(n-1)/n-1;
a = linspace(0, 2*pi, 100);
hold on; %[output:10e1b7a0]
plot(r*cos(a), r*sin(a), 'r-'); %[output:10e1b7a0]
plot(cos(a), sin(a), 'k-'); %[output:10e1b7a0]
hold off; %[output:10e1b7a0]
%%
clear;
figure("Visible", "On");
x = [-1 1 1 -1 -1]';
y = [1 1 -1 -1 1]';

p = 0:0.5:9;
h = plot(x+p, y); %[output:04b700ca]
axis equal; %[output:04b700ca]
axis([-2 11 -2 2]);     %[output:04b700ca]
grid on; %[output:04b700ca]
%%
%사각형 회전
clear;
fig = figure("Visible", "On"); %[output:30c40d3a]
x = [-1 1 1 -1 -1]';
y = [1 1 -1 -1 1]';

h = plot(x,y); %[output:30c40d3a]
axis equal; %[output:30c40d3a]
axis([-2 11 -2 2]);     %[output:30c40d3a]
grid on; %[output:30c40d3a]
hold on; %[output:30c40d3a]

p = linspace(0,-4*pi,100);
filename = "rotating_rectangle.gif";
for k = 1:length(p) %[output:group:31abf238]
    a = p(k);
    c = cos(a); s = sin(a);
    h.XData = c*x - s*y - a; %[output:30c40d3a]
    h.YData = s*x + c*y;
    pause(0.1);
end %[output:group:31abf238]
 %프레임 캡처
 
%%
%[text] ### Multiple Plots
%[text] #### Scaled Squares
%[text] ![](text:image:9790)![](text:image:98db)
% Single Square: 원점 중심, 한변의 길이는 2
x = [-1 1 1 -1 -1];
y = [1 1 -1 -1 1];
plot(x, y) %[output:7df9f301]
axis equal; axis off %[output:7df9f301]
%%
% Scaled Squares: 축소된 10개의 정사각형
x = repmat([-1 1 1 -1 -1], 10, 1)';
y = repmat([1 1 -1 -1 1], 10, 1)';
r = linspace(1,0.1,10);
X = x.*r;
Y = y.*r;
plot(X, Y) %[output:01dfcb92]
axis equal; axis off %[output:01dfcb92]
%%
%[text] ### Circles on a Circle
%[text] 반지름이 5인 원 위에 반지름이 1인 원들이 16개
%[text] ![](text:image:0d18)
% Draw a gray circle, r=5
clear;

a = linspace(0, 2*pi, 161)';
x = cos(a); y = sin(a);
plot(5*x, 5*y, 'Color',[0.5 0.5 0.5]); %[output:14c791c7]
axis equal; axis off; axis(6.1*[-1 1 -1 1]); %[output:14c791c7]
%%
% Draw the circles on the circle
%  원을 16등분한 점을 중심으로 원 그리기 
a = linspace(0, 2*pi, 161)';
b = linspace(0, 2*pi, 16);
x = cos(a); y = sin(a);
cx = cos(b); cy = sin(b);
plot(5*x, 5*y, x+5*cx, y+5*cy); %[output:165129e8]
axis equal; axis off; axis(6.1*[-1 1 -1 1]); %[output:165129e8]
%%
%[text] ### Eyes
%[text] ![](text:image:7cec)
%[text] #### 왼쪽 쳐다보기
n = 100;
t = linspace(0, 2*pi, n)';
x = cos(t);
y = sin(t);
c = 1:5; % center
r = c;   % radius
X = x*r + c;
Y = y*r;
plot(X,Y, X-10,Y, 'LineWidth', 2)  %[output:8fe3936b]
axis equal; %[output:8fe3936b]
%%
%[text] #### 오른쪽 쳐다보기
% Look right
n = 100;
t = linspace(0, 2*pi, n)';
x = cos(t);
y = sin(t);
c = 1:5; % center
r = c;   % radius
X = x*r - c;
Y = y*r;
plot(X,Y, X-10,Y, 'LineWidth', 2)  %[output:123f13ee]
axis equal; %[output:123f13ee]
%%
%[text] #### 눈을 가운데로 모으기
% Look center
% Look right
clear;
n = 100;
t = linspace(0, 2*pi, n)';
x = cos(t);
y = sin(t);
c = 1:5; % center
r = c;   % radius
X = x*r + c;
X2 =  x*r - c
Y = y*r;
plot(X,Y, X2,Y, 'LineWidth', 2)  %[output:6c0186c7]
axis equal; %[output:6c0186c7]
%%
%[text] #### 눈을 치켜뜨기
% Look up
% Look right
clear;

n = 100;
t = linspace(0, 2*pi, n)';
x = cos(t);
y = sin(t);
c = 1:5; % center
r = c;   % radius
X = x*r;
Y = y*r - c;
plot(X,Y, X-10,Y, 'LineWidth', 2)  %[output:1fa2d067]
axis equal; %[output:1fa2d067]
%%
%[text] ### Function Plot
%[text] - `fplot()` 활용하기 \
fplot(@(x) x.^2+4*sin(2*x)-1, [-3 3], 'b-'); %[output:710907f2]
%%
%[text] - `fimplicit()` 활용하기 \
fimplicit(@(x,y) x.^2 - y.^2 - 1); %[output:2f255b78]
%%
%[text] 그래프 속성 변경하기
fp = fimplicit(@(x,y) y.*sin(x) + x.*cos(y) - 1); %[output:2b27cede]
fp.Color = 'r'; %[output:2b27cede]
%%
%[text] ## Curves
%[text] List of Famous Curves
%[text] [https://www.matematica.pt/en/useful/list-curves.php](https://www.matematica.pt/en/useful/list-curves.php)
%%
%[text] ### Lituus Curves
%[text] $r^2 = \\frac{a^2}{\\theta}$
a = 2;
t = linspace(pi/4, 50*pi, 10000);
r = a./sqrt(t);
x = r .* cos(t);
y = r .* sin(t);
plot(x, y, 'r-'); %[output:8cbd29cc]
axis equal; %[output:8cbd29cc]
%%
%[text] ### Astroid
%[text] $x^{2/3}+ y^{2/3} = a^{2/3$
a  = 2;
syms x y
fp = fimplicit((x^2)^(1/3) + (y^2)^(1/3) == 1, [-1 1]); %[output:2e9763c8]
fp.Color = 'r'; %[output:2e9763c8]
axis equal; %[output:2e9763c8]
